<script setup lang="ts">import { ref, watch } from "vue"; import type { MemoryDetail } from "../../types"; const p=defineProps<{detail:MemoryDetail;pending:boolean}>(); const emit=defineEmits<{revise:[value:string];invalidate:[];remove:[];purgeSource:[id:string]}>(); const value=ref(p.detail.memory.value); watch(()=>p.detail.memory.value,v=>value.value=v);</script>
<template><article class="detail"><header><div><small>{{ detail.memory.memory_type }} · {{ detail.memory.status }}</small><h2>{{ detail.memory.subject }} {{ detail.memory.predicate }}</h2></div><strong>{{ Math.round(detail.memory.confidence*100) }}%</strong></header><textarea v-model="value" aria-label="Memory value"/><div class="actions"><button :disabled="pending" @click="emit('revise',value)">Save revision</button><button :disabled="pending" @click="emit('invalidate')">Invalidate</button><button :disabled="pending" class="danger" @click="emit('remove')">Hard delete</button></div><h3>Revision history</h3><ol><li v-for="r in detail.revisions" :key="r.revision_id"><strong>{{ r.value }}</strong><small>{{ new Date(r.valid_from).toLocaleString() }}<template v-if="r.valid_to"> – {{ new Date(r.valid_to).toLocaleString() }}</template> · {{ r.reason }}</small></li></ol><h3>Evidence</h3><ul><li v-for="e in detail.evidence" :key="e.evidence_id"><small>{{ e.source_type }} · {{ new Date(e.source_time).toLocaleString() }}</small><p>{{ e.excerpt }}</p><button :disabled="pending" @click="emit('purgeSource',e.source_document_id || e.source_id)">Clear this source</button></li></ul></article></template>
<style scoped>.detail{padding:1rem;background:var(--bg-panel);border:1px solid var(--border-muted);border-radius:.5rem}.detail header{display:flex;justify-content:space-between}h2{margin:.2rem 0;font-size:1rem}h3{margin-top:1rem;font-size:.78rem}small{display:block;color:var(--text-tertiary)}textarea{width:100%;min-height:5rem;margin:.7rem 0;padding:.55rem;color:var(--text-primary);background:var(--bg-canvas);border:1px solid var(--border-muted)}.actions{display:flex;gap:.4rem}.danger{color:var(--danger)}li{margin:.5rem 0;font-size:.74rem}li p{margin:.2rem 0}</style>
